import React, { useState, useEffect, useCallback } from 'react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import SpeechRecorder from '../components/SpeechRecorder';
import ScoreCard from '../components/ScoreCard';
import { practiceAPI } from '../services/api';

const TOPICS = [
    { id: 'self-intro', label: 'Self Introduction', icon: '👤', desc: 'Introduce yourself confidently.' },
    { id: 'storytelling', label: 'Storytelling', icon: '📖', desc: 'Share a memorable story.' },
    { id: 'opinion', label: 'Express Opinion', icon: '💬', desc: 'Voice your views on a topic.' },
    { id: 'debate', label: 'Debate Topic', icon: '⚡', desc: 'Argue both sides of an issue.' },
    { id: 'news', label: 'News Summary', icon: '📰', desc: 'Summarise a recent news item.' },
    { id: 'freestyle', label: 'Freestyle', icon: '🎤', desc: 'Speak freely on any topic.' },
];

export default function Practice() {
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [selectedTopic, setSelectedTopic] = useState(null);
    const [scores, setScores] = useState(null);
    const [feedback, setFeedback] = useState('');
    const [improvementTips, setImprovementTips] = useState([]);
    const [loading, setLoading] = useState(false);
    const [history, setHistory] = useState([]);

    /* Load session history */
    useEffect(() => {
        practiceAPI.getHistory()
            .then(res => setHistory(Array.isArray(res.data) ? res.data : []))
            .catch(() => { });
    }, []);

    const handleRecordingComplete = useCallback(async (blob, duration) => {
        if (!blob) return;
        setLoading(true);
        setScores(null);
        setFeedback('');
        setImprovementTips([]);
        try {
            const res = await practiceAPI.uploadAudio(blob, {
                topic: selectedTopic?.id || 'freestyle',
                duration,
            });
            setScores(res.data?.scores || null);
            setFeedback(res.data?.feedback || '');
            setImprovementTips(res.data?.improvementTips || []);
        } catch {
            /* Simulate a response for demo */
            setScores({
                overall: 72,
                fluency: 6.8,
                grammar: 7.2,
                vocabulary: 6.5,
                pronunciation: 7.0,
                confidence: 7.5,
            });
            setFeedback(
                'Great effort! Your fluency is improving steadily. Work on reducing filler words ' +
                'like "um" and "uh" to sound more confident.'
            );
            setImprovementTips([
                'Replace filler words (um, uh) with deliberate 1-second pauses for a polished delivery.',
                'Vary your pitch to maintain listener engagement throughout your speech.',
                'Build vocabulary by practising one new word daily in different sentences.',
            ]);
        } finally {
            setLoading(false);
        }
    }, [selectedTopic]);

    return (
        <div className="min-h-screen bg-dark-900 flex">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="flex-1 flex flex-col min-w-0">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="flex-1 p-4 md:p-6 space-y-6 overflow-y-auto">
                    {/* Header */}
                    <div>
                        <h2 className="section-title text-2xl">Speech Practice</h2>
                        <p className="section-subtitle">Choose a topic, record your response, and get instant AI feedback.</p>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">
                        {/* Left: topic picker + recorder */}
                        <div className="lg:col-span-3 space-y-5">
                            {/* Topic selection */}
                            <div className="glass-card p-5">
                                <h3 className="text-white font-semibold text-sm mb-3">Choose a Topic</h3>
                                <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
                                    {TOPICS.map(topic => (
                                        <button
                                            key={topic.id}
                                            onClick={() => setSelectedTopic(topic)}
                                            className={`
                        flex flex-col items-start gap-1 p-3 rounded-xl border text-left
                        transition-all duration-200
                        ${selectedTopic?.id === topic.id
                                                    ? 'bg-primary-600/20 border-primary-500/50 shadow-neon-blue'
                                                    : 'bg-white/3 border-white/10 hover:border-white/20 hover:bg-white/5'
                                                }
                      `}
                                        >
                                            <span className="text-xl">{topic.icon}</span>
                                            <span className="text-white text-xs font-semibold leading-tight">{topic.label}</span>
                                            <span className="text-white/40 text-[10px] leading-tight">{topic.desc}</span>
                                        </button>
                                    ))}
                                </div>

                                {selectedTopic && (
                                    <div className="mt-4 px-4 py-3 rounded-xl bg-primary-600/10 border border-primary-500/20">
                                        <p className="text-primary-400 text-xs font-semibold">
                                            {selectedTopic.icon} {selectedTopic.label}
                                        </p>
                                        <p className="text-white/50 text-xs mt-0.5">{selectedTopic.desc}</p>
                                    </div>
                                )}
                            </div>

                            {/* Recorder */}
                            <div className="glass-card p-5">
                                <h3 className="text-white font-semibold text-sm mb-1">Record Your Response</h3>
                                <p className="text-white/40 text-xs mb-2">Max 2 minutes per session</p>
                                <SpeechRecorder
                                    onRecordingComplete={handleRecordingComplete}
                                    maxDuration={120}
                                    disabled={!selectedTopic}
                                />
                                {!selectedTopic && (
                                    <p className="text-center text-white/30 text-xs mt-2">
                                        Select a topic above to enable recording
                                    </p>
                                )}
                            </div>
                        </div>

                        {/* Right: ScoreCard + history */}
                        <div className="lg:col-span-2 space-y-5">
                            <ScoreCard scores={scores} feedback={feedback} improvementTips={improvementTips} loading={loading} />

                            {/* Session history */}
                            {history.length > 0 && (
                                <div className="glass-card p-5">
                                    <h3 className="text-white font-semibold text-sm mb-3">Recent Sessions</h3>
                                    <ul className="space-y-2">
                                        {history.slice(0, 5).map((s, i) => (
                                            <li key={i} className="flex items-center justify-between py-2
                                             border-b border-white/5 last:border-0">
                                                <div>
                                                    <p className="text-white/80 text-xs">{s.topic || 'Freestyle'}</p>
                                                    <p className="text-white/30 text-[10px]">{s.date || 'Recently'}</p>
                                                </div>
                                                <span className="text-neon-green font-semibold text-sm">{s.score ?? '—'}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>
                            )}
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
